import React from 'react';
import logo from '../assets/ss.png'; // ✅ correct import path

function Header() {

  const currentDate = new Date();
  const weekday = currentDate.toLocaleDateString('en-GB', { weekday: 'long' });
  const day = currentDate.getDate();
  const month = currentDate.toLocaleDateString('en-GB', { month: 'long' });
  const year = currentDate.getFullYear();

  const formattedDate = `${weekday}, ${day} ${month} ${year}`;



  return (
    <header className="relative flex items-center justify-between px-6 py-4 bg-gradient-to-r from-purple-700 via-indigo-700 to-purple-900 shadow-lg">
      <img src={logo} alt="Logo" className="h-10 w-auto" />
      <div className="text-center flex-1">
        <h1 className="text-3xl font-bold text-white">MeetingBot</h1>
        <p className="text-gray-300 text-sm">AI-Powered Audio & Text File Transcription with Summarization</p>
      </div>

      <div className="w-10"></div>

      <div className="absolute bottom-1 right-6">
        <p className="text-sm text-gray-300">{formattedDate}</p>
      </div>
    </header>
  );
}

export default Header;


